const raw = items[0].json.output?.[0]?.content?.[0]?.text || "";
const input = items[0].json;

let parsed;

try {
  const match = raw.match(/\{[\s\S]*\}/);

  if (!match) {
    throw new Error("No JSON found in model output");
  }

  parsed = JSON.parse(match[0]);

} catch (e) {
  throw new Error("Parsing failed: " + raw);
}

return [
  {
    json: {
      keyword: parsed.original_keyword,
      normalized_keyword: parsed.normalized_keyword,
      derived_keywords: parsed.queries,
      vendor_count_requested: input.vendor_count_requested || 5,
      status: "pending",
      source_type: input.source_type || "keyword",
      sources: input.sources || [],
      client_id: 1
    }
  }
];

const runId = $('Create a row').first().json.id;
const input = items[0].json;
const queries = input.derived_keywords || [];

return queries.map((q, index) => ({
  json: {
    search_run_id: runId,
    keyword: input.keyword,
    product_search: q,
    query_index: index
  }
}));

const runId = $node["Create a row"].json.id;
const input = items[0].json;
const markdown = input.data?.markdown;

if (!markdown) return [];

const vendorPattern = /\[([^\]]{3,100})\]\(https?:\/\/(?:export|www)\.indiamart\.com\/company\/([^\/\)\s]+)/g;
let match;
const positions = [];

while ((match = vendorPattern.exec(markdown)) !== null) {
  const slug = match[2];
  if (/^(search|category|login|register|terms|privacy|about|help|contact|products)/i.test(slug)) continue;
  positions.push({ company_name: match[1].trim(), slug, index: match.index });
}

const results = [];
const seenThisPage = new Set();

for (let i = 0; i < positions.length; i++) {
  const { company_name, slug } = positions[i];
  const vendorId = `indiamart_${slug}`;
  if (seenThisPage.has(vendorId)) continue;
  seenThisPage.add(vendorId);

  const start = positions[i].index;
  const end = positions[i + 1] ? positions[i + 1].index : markdown.length;
  const block = markdown.substring(start, end);
  const productMatch = block.match(/\[([^\]]{5,120})\]\(https?:\/\/export\.indiamart\.com\/products\/([^\)]+)\)/);
  const product_name = productMatch ? productMatch[1].trim() : null;
  const product_url = productMatch ? `https://export.indiamart.com/products/${productMatch[2]}` : null;

  let price = null;
  const visiblePriceMatch = block.match(/(?:₹|\$)\s?([\d,]+(?:\.\d+)?)/);
  if (visiblePriceMatch) price = visiblePriceMatch[1];
  if (!price) {
    const urlPriceMatch = block.match(/\|\|\|\|([\d.]+)\|\|product/);
    if (urlPriceMatch) price = urlPriceMatch[1];
  }
  if (price) price = price.replace(/,/g, '');

  const moqMatch = block.match(/MOQ:\s*([\d,]+\s*\w+)/i);
  const moq = moqMatch ? moqMatch[1].trim() : null;
  const ratingMatch = block.match(/★{3,}([\d.]+)\(/);
  const rating = ratingMatch ? parseFloat(ratingMatch[1]) : null;

  const isNumeric = /^\d+$/.test(slug);
  const vendor_url = isNumeric ? `https://export.indiamart.com/company/${slug}/` : `https://www.indiamart.com/${slug}/`;

  results.push({
    json: {
      search_run_id: runId,
      vendor_id: vendorId,
      product_search: input.product_search || null,
      normalized_product: input.normalized_keyword || null,
      fetch_datetime: new Date().toISOString(),
      company_name,
      vendor_url,
      product_name,
      product_url,
      price,
      moq,
      rating,
      source: {
        platform: "IndiaMART",
        raw_snippet: block.slice(0, 300)
      },
      client_id: 1,
      pipeline_status: "scraped_minimal"
    }
  });
}

return results;

const original = $input.first().json;
const markdown = original.data?.markdown;

if (!markdown) {
  throw new Error("No markdown found");
}

const company_name = markdown.match(/^#\s*(.+)/m)?.[1]?.trim() || null;
const location = markdown.match(/\n([A-Za-z\s]+,\s*India)\n/)?.[1]?.trim() || null;
const gstin = markdown.match(/\b\d{2}[A-Z]{5}\d{4}[A-Z]{1}\d[Z][A-Z\d]\b/)?.[0] || null;
const iecMatch = markdown.match(/IEC\s+([A-Z0-9]{10})/);
const iec = iecMatch && /[A-Z]/.test(iecMatch[1]) ? iecMatch[1] : null;
const gst_reg_date = markdown.match(/GST Registration Date\s*\n\n([^\n]+)/i)?.[1]?.trim() || null;
const exporting_since = markdown.match(/Exporting Since\s*([^\n]+)/i)?.[1]?.trim() || null;
const ratingRaw = markdown.match(/Rating:★+([\d.]+)/)?.[1];
const rating = ratingRaw ? parseFloat(ratingRaw) : null;
const verified_exporter = /VerifiedExporter|Verified Exporter/i.test(markdown) ? "YES" : null;
const trust_seal = /TrustSEAL/i.test(markdown) ? "YES" : null;
const established_year = markdown.match(/Established.*?(\d{4})/)?.[1] || null;
const nature_of_business = markdown.match(/Nature of Business\s*\n\n([^\n]+)/i)?.[1]?.trim() || null;
const legal_status = markdown.match(/Legal Status of Firm\s*\n\n([^\n]+)/i)?.[1]?.trim() || null;
const annual_turnover = markdown.match(/Annual Turnover\s*\n\n([^\n]+)/i)?.[1]?.trim() || null;
const num_employees = markdown.match(/(?:Number of Employees|Employees|Workforce)\s*\n\n([^\n]+)/i)?.[1]?.trim() || null;

let company_type = markdown.match(/Business Type\s*\n\n([^\n]+)/i)?.[1]?.trim() || null;
if (!company_type && nature_of_business) company_type = nature_of_business;
if (!company_type) {
  const fallback = markdown.match(/Manufacturer|Exporter|Supplier|Wholesaler/i);
  company_type = fallback ? fallback[0] : null;
}

const export_countries = markdown.match(/Exports?\s*(?:To)?\s*\n\n([^\n]+)/i)?.[1]?.trim() || null;
const addressMatch = markdown.match(/## Contact Us[\s\S]*?\n\n([^\n]+,\s*[^\n]+India)/);
let address = addressMatch ? addressMatch[1].trim() : null;
if (address) {
  const parts = address.split(',').map(p => p.trim());
  address = [...new Set(parts)].join(', ');
}

const contact_person = markdown.match(/Contact Person[:\s]*([^\n]+)/i)?.[1]?.trim() || null;
let phone = null;
const phoneMatches = markdown.match(/(\+91[\s-]?\d{10}|\b\d{10}\b)/g);
if (phoneMatches) {
  phone = phoneMatches.find(p => p.replace(/\D/g, '').length === 10) || null;
}
const email = markdown.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i)?.[0] || null;

const normalize = str => str.toLowerCase().replace(/[^a-z0-9]/g, '');
const productMatches = [...markdown.matchAll(/\[([^\]]+)\]\(https:\/\/export\.indiamart\.com\/products\/\?id=\d+\)/g)];
const products = [...new Map(productMatches.map(p => [normalize(p[1]), p[1].trim()])).values()];

return [
  {
    json: {
      search_run_id: $('Code in JavaScript2').first().json.search_run_id,
      vendor_id: $('Code in JavaScript2').first().json.vendor_id,
      company_name,
      location,
      gstin,
      iec,
      gst_reg_date,
      exporting_since,
      established_year,
      nature_of_business,
      legal_status,
      annual_turnover,
      num_employees,
      company_type,
      export_countries,
      rating,
      verified_exporter,
      trust_seal,
      address,
      contact_person,
      phone,
      email,
      products,
      pipeline_status: "enriched"
    }
  }
];

const seen = new Set();

return items
  .filter(item => item.json.vendor_url)
  .filter(item => {
    if (seen.has(item.json.vendor_url)) return false;
    seen.add(item.json.vendor_url);
    return true;
  })
  .map(item => ({
    json: {
      vendor_url: item.json.vendor_url,
      vendor_id: item.json.vendor_id,
      search_run_id: item.json.search_run_id
    }
  }));

const seen = new Set();

return items
  .filter(item => item.json.vendor_url)
  .filter(item => {
    if (seen.has(item.json.vendor_url)) return false;
    seen.add(item.json.vendor_url);
    return true;
  })
  .slice(0, 5)
  .map(item => ({
    json: {
      vendor_url: item.json.vendor_url,
      vendor_id: item.json.vendor_id,
      search_run_id: item.json.search_run_id
    }
  }));
